const body = $input.first().json.body;
const produto = body.productName || 'Produto';
const margem = parseFloat(body.netMarginPct || 0).toFixed(1);
const precoAtual = parseFloat(body.customPrice || body.suggestedPrice || 0).toFixed(2);
const custoBase = parseFloat(body.baseUnitCost || 0).toFixed(2);
const canal = body.channel === 'ifood' ? 'iFood' : 'Venda Direta';

// Calcula preço mínimo para 15% de margem saudável
const ded = (parseFloat(body.margin || 30) + parseFloat(body.tax || 6) + (body.channel === 'ifood' ? 25 : 0)) / 100;
const precoSugerido = ded < 1 ? (parseFloat(body.baseUnitCost || 0) / (1 - ded)).toFixed(2) : 'N/A';

const mensagem = `🚨 *ALERTA PiTa® — MARGEM PERIGOSA*

*Produto:* ${produto}
*Canal:* ${canal}
*Preço praticado:* R$ ${precoAtual}
*Custo base:* R$ ${custoBase}
*Margem líquida atual:* ${margem}% ⚠️

*Preço sugerido ideal:* R$ ${precoSugerido}

Reajuste o preço ou reduza custos urgentemente para proteger a saúde financeira da PiTa®!`;

return [{ json: { mensagem, produto, margem, precoAtual, precoSugerido } }];
